#include <vector>
#include <algorithm>
using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size), tree(size + 2, 0) {}
    void update(int index, long long delta) {
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

long long compute_depth(long long x) {
    int depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<FenwickTree> ft(5);
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        long long d = compute_depth(x);
        if (d > 4) {
            d = 4;
        }
        ft[d].update(i + 1, 1);
    }
    vector<long long> answer;
    for (auto q : queries) {
        if (q[0] == 1) {
            int l = q[1];
            int r = q[2];
            int k = q[3];
            if (k == 5) {
                answer.push_back(0);
                continue;
            }
            if (k < 0 || k > 4) {
                answer.push_back(0);
                continue;
            }
            long long res = ft[k].range_query(l + 1, r + 1);
            answer.push_back(res);
        } else {
            int idx = q[1];
            long long val = q[2];
            long long old_val = nums[idx];
            long long old_d = compute_depth(old_val);
            ft[old_d].update(idx + 1, -1);
            nums[idx] = val;
            long long new_d = compute_depth(val);
            ft[new_d].update(idx + 1, 1);
        }
    }
    return answer;
}

